using System.ComponentModel;

using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capability so the agent can record key findings during research.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note with a title, content, and optional source URL. " +
                 "Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short title summarizing the note")] string title,
        [Description("The detailed content of the note")] string content,
        [Description("The source URL where this information was found (optional)")] string? sourceUrl = null)
    {
        var note = new Note(title, content, sourceUrl, DateTime.UtcNow);
        _notes.Add(note);
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Returns all notes saved so far during this research session.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var output = $"Research notes ({_notes.Count} total):\n\n";
        for (var i = 0; i < _notes.Count; i++)
        {
            var note = _notes[i];
            output += $"--- Note #{i + 1}: {note.Title} ---\n";
            output += $"{note.Content}\n";
            if (!string.IsNullOrWhiteSpace(note.SourceUrl))
            {
                output += $"Source: {note.SourceUrl}\n";
            }
            output += "\n";
        }

        return output;
    }

    [Description("Deletes a note by its number (1-based index).")]
    public string DeleteNote(
        [Description("The note number to delete (1-based)")] int noteNumber)
    {
        if (noteNumber < 1 || noteNumber > _notes.Count)
        {
            return $"Invalid note number {noteNumber}. There are {_notes.Count} notes.";
        }

        var removed = _notes[noteNumber - 1];
        _notes.RemoveAt(noteNumber - 1);
        return $"Deleted note \"{removed.Title}\".";
    }

    public IReadOnlyList<Note> Notes => _notes.AsReadOnly();

    public IList<AIFunction> CreateFunctions() =>
    [
        AIFunctionFactory.Create(SaveNote, nameof(SaveNote), "Save a research note with a title and content"),
        AIFunctionFactory.Create(GetNotes, nameof(GetNotes), "Get all saved research notes"),
        AIFunctionFactory.Create(DeleteNote, nameof(DeleteNote), "Delete a note by its number"),
    ];

    public sealed record Note(string Title, string Content, string? SourceUrl, DateTime SavedAt);
}

